  for t in triple_list:
              formatter = templates.get(t.predicate)
              if formatter:
                  phrase = formatter(t.subject, t.object)
                  # Determine whether to prepend the subject
                  if phrase.startswith(t.subject):
                      # Phrase already begins with the subject; use as‑is
                      clause_part = phrase
                  elif t.subject in phrase:
                      # Subject appears elsewhere (e.g., "The full name of X is Y")
                      clause_part = phrase
                  else:
                      clause_part = f"{t.subject} {phrase}"
                  suffixes.append(clause_part)
              else:
                  # Fallback for unknown predicates
                  suffixes.append(f"{t.subject} {t.predicate} {t.object}")

          # Combine clauses for the same subject
          if len(suffixes) == 1:
              clause = suffixes[0]
          else:
              clause = " and ".join(suffixes)
